#include <iostream>
#include <algorithm>
using namespace std;
int main()
{
    string s;
    while(getline(cin,s,','))
    {
        int big=0,small=0,num=0,other=0;
        if(s.size()<6||s.size()>12)
        {
            continue;
        }
        for(int i=0;i<=s.size()-1;i++)
        {
            if(s[i]>='A'&&s[i]<='Z')
            {
                big=1;
            }
            else if(s[i]>='a'&&s[i]<='z')
            {
                small=1;
            }
            else if(s[i]>='0'&&s[i]<='9')
            {
                num=1;
            }
            else if(s[i]=='!'||s[i]=='@'||s[i]=='#'||s[i]=='$')
            {
                other=1;
            }
            else
            {
                other=0;
                break;
            }
        }
        int sum=num+big+small;
        if(sum>=2&&other==1)
        {
            cout<<s<<endl;
        }
    }
    return 0;
}
